VALUES
  ('pukao-6f0ba476-moex-00099', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '依據國際會計準則ISA38「無形資產」之規定，發展階段之支出若同時符合下列條件，應認列為 無形資產，請問下列條件何者錯誤？', '["完成該無形資產已達技術可行性，使該無形資產將可供使用或出售", "意圖完成該無形資產，並加以使用或出售", "有能力使用或出售無形資產", "研究階段歸屬於無形資產之支出能可靠衡量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00100', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', 'A公司在X0年12月3 日以每股$20購買B公司25%普通股9,000股。B公司X1年及X2年資 料如下： 公司淨利 每股發放現金股利 年底每股市價 X1年 $100,000 $1 $25 X2年 $100,000 $2 $40 請問 A 公司若將投資 B 公司股票列入採權益法之投資或列入透過損益按公允價值衡量之金融資 產，則對A公司X2年度損益之影響，何者正確？', '["採權益法之投資淨利增加$45,000", "採權益法之投資淨利增加$35,000", "透過損益按公允價值衡量之金融資產淨利增加$153,000", "透過損益按公允價值衡量之金融資產淨利增加$135,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "20780e87fbd7", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00101', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'essay', '甲與乙於民國 109 年 2 月結婚，卻於結婚後的次月，即因細故大吵，甲
憤而將菸灰缸砸向乙，乙頭破血流，隨即前往醫院救治。乙為求婚姻和
睦，出院後絕口不提此事，怎料二人仍爭吵不斷，遂於民國 111 年 2 月
協議離婚。乙心有不甘，於民國 112 年 10月要求甲就菸灰缸砸傷自己一
事賠償損害，但遭甲以時日已久為由斷然拒絕。請問：甲或乙何人之主
張有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00102', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'essay', '甲經商有成，允諾要將其名下 A屋贈與其女友乙，並請公證人將A屋贈
與契約作成公證書。怎料，半年後，甲因周轉不靈，公司倒閉並負債累
累。請問：甲得否拒絕履行對乙之贈與契約？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00103', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於已登記土地被他人侵占之返還請求權消滅時效，下列敘述，何者正確？', '["無消滅時效之適用", "時效期間為2年", "時效期間為5年", "時效期間為15年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00104', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於消滅時效與除斥期間之敘述，何者錯誤？', '["消滅時效所適用之客體，包括請求權與支配權", "撤銷權、解除權、終止權等為形成權，法律關於該等權利所規定之存續期間，即係除斥期間", "時效中斷所稱請求，係指訴訟外之請求", "消滅時效之不完成，非源自權利人行使權利或義務人承認權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00105', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列法律行為，何者屬於不要式行為?', '["結婚行為", "設立財團之捐助行為", "設立社團章程", "代理權之授與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00106', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '未成年高職生甲於父母親不知情下，應徵乙公司之工作。為符合錄取條件，甲將戶籍謄本之偽造 抄本，出示於乙公司，使乙公司信其為成年人。嗣後雙方訂立僱傭契約。此僱傭契約之效力為何？', '["不成立", "效力未定", "有效", "無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00107', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲社團法人，有董事A及其四名子女（B、C、D、E）共五人，B從小乖巧，聰穎過人，深得A 之信賴。甲社團法人乃於章程規定，僅A與B對外有代表權，其餘董事均無代表權，但於法人登 記時，卻未將上情為登記。C見A偏頗，擔心獨厚B，乃提議並經社團總會決議，若甲社團法人 出售不動產時，必須經全體董事同意。下列敘述，何者正確？', '["若C以甲之名義，向乙公司購買機器，因乙早就知悉章程規定，故C與乙所訂立之機器買賣契 約，對甲不生效力", "甲社團法人章程規定，僅A與B有代表權，但漏未登記，即不生法律效力，五名董事對外仍有 代表權", "若A及C將甲之土地出售於丙，丙並不知社團總會決議，故丙得主張其為善意第三人，對甲有 對抗效力", "為保護交易第三人，章程規定及社團總會決議，均屬應登記事項，若未經登記，不得對抗善意 第三人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00108', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲被乙欺騙，與乙約定以新臺幣（下同）20萬元買受乙僅值2萬元之A物。下列敘述，何者正確？', '["該Ａ物之買賣契約無效", "甲之意思表示有效，但得撤銷", "甲得訴請法院撤銷該Ａ物之買賣契約", "甲之意思表示，不生效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
